package com.Myloop;
import java.util.*;
public class MyLoops {

	public static void main(String[] args) {
		Scanner sc = new Scanner(System.in);
		int n = sc.nextInt();
		for (int i = 1;i<=10;i++) {
			int product = n*i;
			System.out.println(n+" * "+i+" = "+product);
		}
		
		// TODO Auto-generated method stub

	}

}
